<template>
    <section>
        <div class="my-popups">
            <div class="modal my-popups right fade d-block" :class="{ show: isShown }">
                <div role="document" class="modal-dialog" style="max-width: 1400px !important;">
                    
                    <div class="modal-content">
                        <div class="modal-header mheader-user">
                            <button class="close" v-on:click="ClosePopUp">
                                <em aria-hidden="true" class="fa fa-times"></em>
                            </button>
                            <h4 name="header" class="modal-title">
                                {{ isBillingType ? $t('ManageServices') : $t('Conditions') }}
                            </h4>
                            
                        </div>
                        <div class="modal-body csscontrol_popup">
                            <div class="heading-border mb-2">
                                <h5 class="h5">
                                    <span> {{ isBillingType ? $t('BillingService') : $t('Billing Conditions') }}</span>
                                    <small class="float-right">
                                        <a class="" title="" id="ancCreateNewService" href="javascript:;"
                                            data-toggle-tooltip="tooltip" :data-original-title="isBillingType ? $t('CreateNewService') : $t('CreateNewCondition')"
                                            v-on:click="AddBillingRule()">
                                            <i class="fa fa-plus pr-2"></i>  {{ isBillingType ? $t('CreateNewService') : $t('CreateNewCondition') }}
                                        </a>
                                    </small>
                                </h5>
                            </div>
                            <div class="listing">
                                <!-- SEARCH DIV -->
                                <div class="row">
                                    <div class="col-3 pb-3">
                                        <input type="text" class="form-control" :placeholder="isBillingType ? 'Search By Service Name' : 'Search By Condition Name'"
                                            v-model="searchvalue" />
                                    </div>
                                    <div class="col-2">
                                        <a class="btn btn-success mr-2 px-4" @click="getConditionRecords"><em
                                                class="fa fa-search"></em></a>
                                        <a class="btn btn-danger px-4" @click="Refreshlist"><em
                                                class="fa fa-refresh"></em></a>
                                    </div>
                                </div>
                                <!-- END SEACRCH DIV -->
                                <div class="table-responsive table-fix-header">
                                    <table class="table table-bordered">
                                        <thead class="thead-bg">
                                            <tr>
                                                <th style="width: 20px;"></th>
                                                <th>{{ isBillingType ? $t('ServiceName') : $t('ConditionName') }}</th>
                                                <th v-show="isBillingType">{{ $t("SACategoryName") }}</th>
                                                <th>{{ isBillingType ? $t('IsLeafNode') : $t('Apply') + ' ' + $t('Rate') }}</th>
                                                <th>{{ $t("Flag") }}</th>
                                                <th>{{ $t('RateCode') }}</th>
                                                <th class="text-center">{{ $t("Action") }}</th>
                                            </tr>
                                        </thead>
                                        <tbody>
                                            <tr v-if="filteredConditions.length > 0" v-for="itm in filteredConditions">
                                                <td>
                                                    <div class="custom-control custom-radio custom-control-inline">
                                                        <input type="radio" :value="itm.SERVICEID"
                                                            v-model="ConditionSelected"
                                                            class="chkItems custom-control-input"
                                                            :name="'RadioForCondition'"
                                                            v-on:change="onConditionSelect(itm, this)" />
                                                        <label type="radio" class="custom-control-label"></label>
                                                    </div>
                                                </td>
                                                <td>{{ itm.SERVICENAME }}</td>
                                                <td v-show="isBillingType">{{ itm.CATEGORY }}</td>
                                                <td>
                                                    <div
                                                        :class="{ 'custom-control custom-checkbox custom-control-inline': true, 'disabled': (ConditionSelected != itm.SERVICEID) }">
                                                        <input type="checkbox" :value="itm.SERVICEID"
                                                            v-model="itm.isLeafChecked"
                                                            :class="{ 'chkItems custom-control-input': true, 'disabled': (ConditionSelected != itm.SERVICEID) }"
                                                            :id="'checkbox_' + itm.SERVICEID" />
                                                        <label type="checkbox" class="custom-control-label"></label>
                                                    </div>
                                                </td>
                                                <td style="overflow: visible !important;">
                                                    <div style="position:relative;">
                                                        <div class="flag-selector">
                                                            <span @click="isLeafTogglePopup(itm)"
                                                                :class="{ 'flag-icon': true, 'disabled-class': (!itm.isLeafChecked || (itm.rateCode != '' && itm.rateCode != null && itm.rateCode != undefined))}"
                                                                :style="{ color: itm.selectedFlag.color }">
                                                                <i class="fas fa-flag"></i>
                                                            </span>

                                                            <!-- Flag condition popup -->
                                                            <div v-if="itm.showPopup" class="popup">
                                                                <div class="popup-header">
                                                                    <span>Flag Condition</span>
                                                                    <button @click="itm.showPopup = false"
                                                                        class="close-btn">×</button>
                                                                </div>
                                                                <div class="flags">
                                                                    <span v-for="flag in flags" :key="flag.value"
                                                                        class="flag-option"
                                                                        @click="isLeafSelectFlag(itm, flag)"
                                                                        :style="{ color: flag.color }">
                                                                        <i class="fas fa-flag"></i>
                                                                    </span>
                                                                </div>
                                                            </div>
                                                        </div>
                                                    </div>
                                                </td>
                                                <td>
                                                    <select
                                                        :class="{ 'form-control': true, 'disabled': (ConditionSelected != itm.SERVICEID || itm.isLeafChecked == false || itm.selectedFlag.value != 'N'), 'border-danger': itm.hasValidationError }"
                                                        v-model="itm.rateCode"
                                                        @change="clearValidationError(itm)">
                                                        <option value="">Select</option>
                                                        <option v-for="ratecode in workCodeList"
                                                            :value="ratecode.value">{{ ratecode.name }}</option>
                                                    </select>
                                                </td>
                                                <td class="single-action text-center" style="width: 100px;">
                                                    <a :class="{ 'actions-onclick': true, 'disabled': (ConditionSelected != itm.SERVICEID) }" 
                                                        v-if="isBillingType" 
                                                        href="javascript:;" 
                                                        title="Edit"
                                                        v-on:click="ConditionSelected == itm.SERVICEID ? EditBillingRule(itm) : null">
                                                        <em :class="{ 'fa fa-pencil action-icon': true, 'text-primary': (ConditionSelected == itm.SERVICEID), 'text-muted': (ConditionSelected != itm.SERVICEID) }"></em>
                                                    </a>
                                                    <a :class="{ 'actions-onclick': true, 'disabled': (ConditionSelected != itm.SERVICEID) }" 
                                                        v-if="!isBillingType" 
                                                        href="javascript:;" 
                                                        title="View"
                                                        v-on:click="ConditionSelected == itm.SERVICEID ? ViewBillingRule(itm) : null">
                                                        <em :class="{ 'fa fa-eye action-icon': true, 'text-success': (ConditionSelected == itm.SERVICEID), 'text-muted': (ConditionSelected != itm.SERVICEID) }"></em>
                                                    </a>
                                                </td>
                                            </tr>
                                            <tr v-if="filteredConditions.length == 0">
                                                <td colspan="6" class="text-danger text-center border-0">
                                                    {{ $t("NorecordfoundText") }}</td>
                                            </tr>
                                        </tbody>
                                    </table>
                                </div>
                                <Pager :numberofrecords="TotalRecords" :callbackfunction="getConditionRecords"
                                    :prevText="$t('Previous')" :nextText="$t('Next')" :firstText="$t('First')"
                                    :lastText="$t('Last')" v-on:SetCurrentPage="SetCurrentPage"></Pager>
                            </div>
                        </div>
                        <div class="modal-footer">
                            <div>
                                <button class="btn btn-success mr-2" v-on:click="saveSelectedRateCode"><em
                                        class="fa fa-save"></em> {{ $t("Save") }}</button>
                                <button class="btn btn-danger" v-on:click="$emit('close')"><em class="fa fa-times"></em>
                                    {{ $t("Cancel") }}</button>
                            </div>
                        </div>
                    </div>
                </div>
            </div>
        </div>
        <ModalAddBillingRule v-if="isModalAddRule" :reqFrom="reqFrom"
            :conditionId="conditionId" :nodeName="nodeName" :configurationId="configurationId" :reqType="reqType"
            @rule-saved="handleRuleSaved" viewType="serviceRuleCondition" :serviceId="serviceId"></ModalAddBillingRule>

        <ManageBillingRuleForm v-if="isManageBillingRuleForm" :reqFrom="reqFrom" 
             :configurationId="configurationId"
            :conditionId="conditionId" :nodeName="nodeName" @rule-saved="handleRuleSaved" viewType="serviceRuleCondition" :serviceId="serviceId" :setupId="setupId" 
            :isBillingType="isBillingType" :clientId="clientId">
        </ManageBillingRuleForm>
        <RuleServiceUpdate 
            v-if="isRuleServiceUpdateFormVisible" 
            :configurationId="configurationId"
            :billingServiceId="BILLING_SERVICE_ID"
            :conditionId ="conditionId"
            :nodeName="nodeName"
            reqFrom="ViewBillingConditionForService"
            closeModalType="isRuleServiceUpdateFormVisible"/>
    </section>
</template>
<script>
import DataService from '../../../services/DataService';
import Pager from '../../../components/Common/Pager.vue';
import ModalAddBillingRule from "../../../components/Modals/modalAddBillingRule.vue";
import RuleServiceUpdate from '../../../views/BillingRule/BillingRuleHistory/RuleServiceUpdate.vue';
import ManageBillingRuleForm from "../../../components/Modals/manageBillingRuleFormForUsic.vue";
import { nodeName } from 'jquery';
export default {
    components: { Pager, ModalAddBillingRule,RuleServiceUpdate,ManageBillingRuleForm },
    props: {
        serviceRuleItem: {
            type: Array,
            required: false
        },
        configurationId: {
            type: Number,
            required: false
        },
        reqType: {
            type: String,
            required: false
        },
        serviceId: {
            type: Number,
            required: false
        },
        isBillingType :{
            type: Boolean,
            required: false
        },
        clientId: {
             type: Number,
            required: false
        },
        setupId: {
             type: Number,
            required: false
        },
        nodeList:{
             type: Array,
            required: false
        },
        rulesArray:{
            type: Array,
            required: false
        }
    },
    data: function () {
        return {
            isRuleServiceUpdateFormVisible:false,
            searchvalue: '',
            conditions: [],
            PageSize: 10,
            PageNumber: 1,
            SortBy: "",
            SortExp: "",
            Headers: [
                {
                    "COLUMN_NAME": "SERVICENAME",
                    "DATA_TYPE": "string",
                    "SORTABLE": false,
                    "VISIBLE": true,
                    "DISPLAY_NAME": this.$t("ServiceName"),
                    "DISPLAY_ORDER": 1
                },
                {
                    "COLUMN_NAME": "CATEGORY",
                    "DATA_TYPE": "string",
                    "SORTABLE": false,
                    "VISIBLE": true,
                    "DISPLAY_NAME": this.$t("Category"),
                    "DISPLAY_ORDER": 1
                },
                {
                    "COLUMN_NAME": "CATEGORY",
                    "DATA_TYPE": "string",
                    "SORTABLE": false,
                    "VISIBLE": true,
                    "DISPLAY_NAME": this.$t("Category"),
                    "DISPLAY_ORDER": 1
                },
            ],
            listActions: [],
            TotalRecords: 0,
            flags: [
                { value: 'R', color: 'red' },
                { value: 'Y', color: 'gold' },
                { value: 'G', color: 'green' },
                { value: 'N', color: 'grey' },
            ],
            ConditionSelected: 0,
            isModalAddRule: false,
            reqFrom: '',
            // PlanId: null,
            workCodeList: [],
            conditionId: 0,
            FlagValue: null,
            configurationId:0,
            nodeName:0,
            billingServiceId:0,
            ruleData:[],
            isManageBillingRuleForm:false,
            isShown: false,
            oldConfigId:0
        }
    },
    created: function () {
        this.getConditionRecords();
        this.BindWorkCode();
         this.oldConfigId = this.$route.params.ocId;
        // this.PlanId = parseInt(this.$route.params.id);
    },
    mounted() {
        this.$nextTick(() => {
            setTimeout(() => {
                this.isShown = true;  // adds .show ? triggers transform transition
            }, 50);
        });
    },
    computed: {
        filteredConditions() {
            if (!this.rulesArray || this.rulesArray.length === 0) {
                return this.conditions;
            }
            // Get all conditionIds from rulesArray
            const existingConditionIds = this.rulesArray
                .filter(rule => rule.ruleCondition && rule.ruleCondition.conditionId)
                .map(rule => rule.ruleCondition.conditionId);
            
            // Filter out conditions that already exist in rulesArray
            return this.conditions.filter(item => !existingConditionIds.includes(item.SERVICEID));
        }
    },
    methods: {
        Refreshlist() {
            this.searchvalue = '';
            this.getConditionRecords();
        },
        handleRuleSaved(ruleData) {
            // if(JSON.parse(ruleData).rateToggle){
            //     this.ruleData=JSON.parse(ruleData);
            // }
        },
        AddBillingRule: function () {
            var vm = this;
            vm.conditionId = 0;
            vm.reqFrom = 'addMapBillingRuleForService';
            // vm.configurationId=this.configurationId;
            vm.nodeName= this.serviceRuleItem.version;
            vm.setupId = this.setupId;
            if(vm.isBillingType){
                vm.isManageBillingRuleForm = true;
            }
            else{
                vm.isModalAddRule = true;
            }
        },
        EditBillingRule: function (item) {
            var vm = this;
            vm.clientId = vm.clientId;
            vm.configurationId=item.CONFIGURATION_ID != null ? item.CONFIGURATION_ID : this.configurationId ;
            vm.nodeName= item.DISPLAY_NODE_NAME != null ? item.DISPLAY_NODE_NAME : this.serviceRuleItem.version;
            vm.conditionId = item.SERVICEID;
            vm.setupId = item.SETUP_ID;
            vm.reqFrom = 'EditMapBillingRuleForService';
            if(vm.isBillingType){
                vm.isManageBillingRuleForm = true;
            }
            else{
                vm.isModalAddRule = true;
            }
           
        },
        ViewBillingRule: function (item) {
            var vm = this;
            vm.configurationId=item.CONFIGURATION_ID;
            vm.nodeName= item.DISPLAY_NODE_NAME;
            vm.conditionId = item.SERVICEID;
            vm.billingServiceId = item.BILLING_SERVICE_ID;
            vm.isRuleServiceUpdateFormVisible = true;
        },
        saveSelectedRateCode: function () {
            var ths = this;
            // Validate if any service is selected
            if (!ths.ConditionSelected || ths.ConditionSelected === 0) {
                ths.ShowAlert(ths.$t('SelectAnyServiceFromList'), "warning", true, ths.$t("Alert"));
                return;
            }
            var selectedRateCode = this.conditions.find(x => x.SERVICEID == ths.ConditionSelected);
            // Additional check if selectedRateCode is not found
            if (!selectedRateCode) {
                ths.ShowAlert(ths.$t('SelectAnyServiceFromList'), "warning", true, ths.$t("Alert"));
                return;
            }
            // Validate if isLeafChecked is true, then at least flag OR work code must be selected
            if (selectedRateCode.isLeafChecked) {
                const isFlagNotSelected = !selectedRateCode.selectedFlag || selectedRateCode.selectedFlag.value === 'N';
                const isWorkCodeNotSelected = !selectedRateCode.rateCode || selectedRateCode.rateCode === '';
                // Show error only if BOTH are not selected
                if (isFlagNotSelected && isWorkCodeNotSelected) {
                    selectedRateCode.hasValidationError = true;
                    ths.ShowAlert(ths.$t('CorrectHighlightedErrors'), 'warning', ths.$t('Alert'));
                    return;
                } else {
                    selectedRateCode.hasValidationError = false;
                }
            }
            
            var obj = {
                conditionId: selectedRateCode.SERVICEID,
                conditionName: selectedRateCode.SERVICENAME,
                serviceName: selectedRateCode.SERVICENAME,
                condition: selectedRateCode.CONDITION,
                categoryId: selectedRateCode.CATEGORYID,
                rateCode: selectedRateCode.rateCode,
                isLeafChecked: selectedRateCode.isLeafChecked,
                selectedFlag: selectedRateCode.selectedFlag,
                isUpdateArray: 1,
                ruleArray: this.ruleData
                // parentServiceId : this.serviceId
            }
            this.serviceRuleItem.ruleCondition = obj;
            // if(this.isBillingType){
            //     var jsonobj = {
            //                     "serviceId": selectedRateCode.SERVICEID,
            //                     "nodeName": this.serviceRuleItem.version,
            //                     "parentServiveId": this.serviceId,
            //                     "clientId": this.clientId,
            //                     "isLeafNode": selectedRateCode.isLeafChecked,
            //                     "leafNodeAmount": 0,
            //                     "configurationId": this.configurationId,
            //                     "serviceName": selectedRateCode.SERVICENAME,
            //                     "serviceCondition": selectedRateCode.CONDITION,
            //                     "summaryInvoiceName": null,
            //                     "parentMappingId": 0,
            //                     "isLimit": false,
            //                     "limitValue": 0,
            //                     "dayLimit": 0,
            //                     "workCode": selectedRateCode.rateCode,
            //                     "flag": selectedRateCode.selectedFlag.value
            //         }
            //                 // var params = JSON.stringify(jsonobj);
                        
            //     DataService.UseExistingService(jsonobj).then((response) => {
            //                     if(response.data.status =='Success')
            //                     {  
            //                          let obj = {
            //                             ConnfigurationId: this.configurationId,
            //                             DisplayOrder: this.nodeList.length + 1,
            //                             NodeName: this.serviceRuleItem.version,
            //                             ServiceId: selectedRateCode.SERVICEID,
            //                             ClientServiceMappingId: 0,
            //                             OriginalConfigId: this.oldConfigId,
            //                             ClientId: this.clientId,
            //                             Type: "S"
            //                         };
            //                         ths.nodeList.push(obj);
            //                         vm.ShowAlert(vm.$t("SuccessfullySaved", [vm.$t("Service")]), "success", true, vm.$t("Alert"));
            //                         this.$emit("close");
            //                     }
            //                     // if (response.data.status == 'Success') {
            //                     //     if (vm.ResourceTypeId > 0) {
            //                     //         vm.ShowAlert(vm.$t("UpdatedSuccess", [vm.$t("Resource")]), "success", true, vm.$t("Alert"));
            //                     //         vm.Close();
            //                     //     }
            //                     //     else {
            //                     //         vm.ShowAlert(vm.$t("AddedSuccess", [vm.$t("Resource")]), "success", true, vm.$t("Alert"));
            //                     //     }
            //                     //     vm.Close();
            //                     //     vm.$parent.FetchResources();
            //                     // }
            //                     // else {
            //                     //     vm.ShowAlert(vm.$t("AddedError", [vm.$t("Resource")]), "failure", true, vm.$t("Alert"));
            //                     //     vm.Close();
            //                     // }
            //     });
            // }
            // else
            // {
                this.$emit("close");
            // }
        },
        BindWorkCode: function () {
            var vm = this;
            if(vm.isBillingType){
                DataService.GetWorkCodeInfo().then((response) => {
                    if (response.data != '' && response.data != null) {
                        if (response.data.length > 0) {
                            vm.workCodeList =response.data;
                        }
                    }
                });
            }
            else{
                var params = "id=&moduleName=&type=WORK_CODE_BY_PLAN_ID&search=&refId=" + this.configurationId;
                DataService.GetDDLData(params).then((response) => {
                    if (response.data) {
                        var json = response.data;
                        if (json != null) {
                            vm.workCodeList = response.data.DATA;
                        }
                    }
                })
            }
           
        },
        onConditionSelect: function (item, e) {
            var ths =  this;
            ths.conditions.forEach(element => {
                if(element.SERVICEID != ths.ConditionSelected) {
                    element.isLeafChecked = false;
                    element.rateCode = "";
                    element.selectedFlag = { value: 'N', color: 'grey' };
                    element.hasValidationError = false;
                }
            });
        },
        clearValidationError: function (item) {
            item.hasValidationError = false;
        },
        SetCurrentPage: function (x) {
            this.PageNumber = x.PageNumber;
            this.PageSize = x.PageSize;
        },
        renderActions: function (row) {
            var self = this;
            let rtnActionArray = [];
            self.listActions.forEach(actionItem => {
                let action = { ...actionItem };
                switch (action.title) {
                    case 'Delete':
                        action.isVisible = true;
                        break;
                    case 'Map Rule':
                        action.isVisible = true;
                        break;
                    default: {
                        action.isVisible = true;
                    }
                }
                rtnActionArray.push(action);
            });
            return rtnActionArray;
        },
        ClosePopUp: function () {
            this.$parent.serviceDetailConditions = false;
              this.$nextTick(() => {
                setTimeout(() => {
                    this.isShown = true;  // adds .show ? triggers transform transition
                }, 50);
            });
        },
        getConditionRecords: function () {
            var vm = this;
            const url = `isIncludeGlobal=false&pageSize=${vm.PageSize}&pageNumber=${vm.PageNumber}&sortBy=${vm.SortBy}&sortExp=${vm.SortExp}&servicename=${vm.searchvalue}&categoryId=&createdBy=`;
            DataService.GetBillServiceListing(url).then(function (response) {
                if (response && response.data != null && response.data.length > 0) {
                    response.data.forEach(function (item) {
                        item.isLeafChecked = false;
                        item.showPopup = false;
                        item.rateCode = "";
                        item.selectedFlag = { value: 'N', color: 'grey' };
                        item.hasValidationError = false;
                    })
                    vm.conditions = response.data;
                    vm.TotalRecords = vm.conditions[0].TOTALRECORDS
                }
                else {
                    vm.conditions = [];
                    vm.TotalRecords = 0;
                }
            })
        },
        isLeafTogglePopup(item) {
            item.showPopup = !item.showPopup;
        },
        isLeafSelectFlag(item, flag) {
            item.selectedFlag = flag;
            item.showPopup = false;
        },
    }
}
</script>
<style scoped>
.border-danger {
    border: 2px solid #dc3545 !important;
}
</style>

